#!/usr/bin/env python3
import os, base64, re
b64 = ''
path = "app\\settings\\page.tsx"
path = path.replace("\\\\", os.sep).replace("\\", os.sep)
content = base64.b64decode(b64).decode("utf-8")
# Always clean double as const before writing
content = re.sub(r"as const(\s+as const)+", "as const", content)
with open(path, "wb") as f:
    f.write(content.encode("utf-8"))
print("Done — git add . && git commit -m \"Fix settings delete and as const\" && vercel --prod")
